UPDATE public.master_wilayah_spx m
SET is_serviceable = FALSE
FROM non_coverage nc
WHERE regexp_replace(UPPER(TRIM(m.state)), '\s+', ' ', 'g') = nc.state
  AND regexp_replace(UPPER(TRIM(m.city)), '\s+', ' ', 'g') = nc.city;
